import jwt
from datetime import datetime, timedelta

SECRET_KEY = 'Your_Secret_Key'  # replace this with your secret key
ALGORITHM = 'HS256'   # algorithm for signing the JWT
ACCESS_TOKEN_EXPIRE_MINUTES = 30  # token expiration time in minutes

def create_access_token(user_id: str, user_role:str):
    expires_delta = timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode = {"exp": datetime.utcnow() + expires_delta, "sub": user_id, "role":user_role}
    encoded_jwt = jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)
    return encoded_jwt